<?php require_once __DIR__.'/../config/database.php'; require_once __DIR__.'/../includes/functions.php'; require_login(); $id=(int)($_GET['id']??0); $stmt=$pdo->prepare('SELECT c.*,d.*,r.code rule_code FROM consultations c JOIN diagnosis_results d ON d.consultation_id=c.id LEFT JOIN rules r ON r.id=d.rule_id WHERE c.id=?'); $stmt->execute([$id]); $row=$stmt->fetch(); if(!$row) die('Data tidak ditemukan'); [$color,$defaultRec]=diagnosis_meta($row['diagnosis']); $riskClass='risk-'.strtolower(str_replace(' ','-', $row['diagnosis'])); $details=$pdo->prepare('SELECT v.code vcode,s.code scode,s.name FROM consultation_details cd JOIN variables v ON v.id=cd.variable_id JOIN symptoms s ON s.id=cd.symptom_id WHERE cd.consultation_id=?'); $details->execute([$id]); require_once __DIR__.'/../includes/header.php'; ?>
<div class="container px-3 px-lg-4 container-narrow"><div class="result-hero mb-4"><div class="d-flex flex-column flex-md-row justify-content-between gap-3"><div><span class="badge-risk <?=$riskClass?>">Potensi <?=e($row['diagnosis'])?></span><h2 class="section-title mt-3 mb-1">Hasil Diagnosa</h2><p class="text-muted mb-0"><i class="bi bi-geo-alt me-1"></i><?=e($row['location'])?> • <?=e($row['created_at'] ?? '')?></p></div><button class="btn btn-outline-primary align-self-start" data-print><i class="bi bi-printer me-2"></i>Print</button></div></div>
<div class="row g-3"><div class="col-lg-7"><div class="card p-4 h-100"><h5 class="fw-bold">Working Memory</h5><p class="text-muted">Fakta yang diterima mesin dari form konsultasi.</p><?php foreach($details->fetchAll() as $d): ?><span class="wm-code"><?=e($d['vcode'])?>: <?=e($d['scode'])?> - <?=e($d['name'])?></span><?php endforeach; ?><hr><h5 class="fw-bold">Rule yang Dipakai</h5><p class="mb-0"><?=e($row['rule_code'] ?: 'R-DEFAULT')?> - <?=e($row['explanation'])?></p></div></div><div class="col-lg-5"><div class="card p-4 h-100"><h5 class="fw-bold">Rekomendasi</h5><p><?=e($row['recommendation'] ?: $defaultRec)?></p><h6 class="fw-bold">Rule Aktif</h6><p class="text-muted"><?=e(implode(', ',json_decode($row['active_rules'],true)?:[]))?></p><h6 class="fw-bold">Rule Gagal</h6><p class="text-muted mb-0"><?=e(implode(', ',json_decode($row['failed_rules'],true)?:[]))?></p></div></div></div>
<div class="card p-4 mt-3"><h5 class="fw-bold mb-3">Timeline Inferensi</h5><div class="timeline"><?php foreach(json_decode($row['inference_trace'],true)?:[] as $t): ?><div class="timeline-item"><b><?=e($t['rule']['code'])?></b> <span class="badge <?=$t['matched']?'text-bg-success':'text-bg-secondary'?> ms-2"><?= $t['matched']?'Fire Rule':'Gagal' ?></span><div class="text-muted mt-1">Diagnosis target: <?=e($t['rule']['diagnosis'])?>. <?=e($t['note'] ?? '')?></div></div><?php endforeach; ?></div></div></div>
